<?php
require_once __DIR__ . '/app/auth.php';
require_login();
require_once __DIR__ . '/app/layout.php';
$pdo=db();
$s=app_stats($pdo);
$month=current_month();
$due=$pdo->query("SELECT c.*,p.name package_name,p.price FROM customers c LEFT JOIN packages p ON p.id=c.package_id ORDER BY c.due_day ASC,c.name ASC LIMIT 8")->fetchAll();
$last=$pdo->query("SELECT pay.*,c.name customer_name FROM payments pay JOIN customers c ON c.id=pay.customer_id ORDER BY pay.paid_at DESC,pay.id DESC LIMIT 8")->fetchAll();
$customerSql="SELECT c.*,p.name package_name,p.price,(SELECT COUNT(*) FROM payments pay WHERE pay.customer_id=c.id AND pay.invoice_month=?) is_paid FROM customers c LEFT JOIN packages p ON p.id=c.package_id ORDER BY c.name ASC LIMIT 12";
$stmt=$pdo->prepare($customerSql); $stmt->execute([$month]); $dashCustomers=$stmt->fetchAll();
$stmt=$pdo->prepare("SELECT c.*,p.name package_name,p.price,(SELECT COUNT(*) FROM payments pay WHERE pay.customer_id=c.id AND pay.invoice_month=?) is_paid FROM customers c LEFT JOIN packages p ON p.id=c.package_id WHERE (SELECT COUNT(*) FROM payments pay WHERE pay.customer_id=c.id AND pay.invoice_month=?) > 0 ORDER BY c.name ASC LIMIT 12"); $stmt->execute([$month,$month]); $dashPaid=$stmt->fetchAll();
$stmt=$pdo->prepare("SELECT c.*,p.name package_name,p.price,(SELECT COUNT(*) FROM payments pay WHERE pay.customer_id=c.id AND pay.invoice_month=?) is_paid FROM customers c LEFT JOIN packages p ON p.id=c.package_id WHERE (SELECT COUNT(*) FROM payments pay WHERE pay.customer_id=c.id AND pay.invoice_month=?) = 0 ORDER BY c.due_day ASC,c.name ASC LIMIT 12"); $stmt->execute([$month,$month]); $dashUnpaid=$stmt->fetchAll();
function dashboard_customer_rows(array $rows, string $empty): void { foreach($rows as $c): ?>
<tr><td data-label="ID"><b><?=e($c['customer_code'])?></b><br><small class="text-slate-500"><?=e($c['phone'] ?? '')?></small></td><td data-label="Nama"><b><?=e($c['name'])?></b><br><small class="text-slate-500"><?=e($c['address'] ?? '')?></small></td><td data-label="Paket"><?=e($c['package_name'] ?? '-')?><br><b><?=rupiah($c['price'] ?? 0)?></b></td><td data-label="Tempo">Tgl <?=e($c['due_day'])?></td><td data-label="Status"><span class="pill <?=$c['is_active']?'green':'red'?>"><?=$c['is_active']?'ON':'OFF'?></span> <span class="pill <?=$c['is_paid']?'green':'orange'?>"><?=$c['is_paid']?'Lunas':'Belum'?></span></td><td data-label="Aksi"><div class="table-actions"><a class="btn soft xs" href="customers.php?edit=<?=$c['id']?>">Edit</a><a class="btn primary xs" href="payments.php?customer_id=<?=$c['id']?>">Bayar</a></div></td></tr>
<?php endforeach; if(!$rows): ?><tr><td colspan="6"><?=e($empty)?></td></tr><?php endif; }
render_header('Dashboard Billing'); ?>
