  <a class="card metric status-card status-blue" href="customers.php"><div class="status-icon">👥</div><small>Data Pelanggan</small><strong><?=$s['total']?></strong><span class="pill blue">Semua pelanggan</span><span class="more-link">Buka data →</span></a>
