  <a class="card metric status-card status-cyan" href="reports.php"><div class="status-icon">↗</div><small>Pemasukan Hari Ini</small><strong><?=rupiah($s['todayIncome'])?></strong><span class="pill green">Hari ini</span><span class="more-link">Detail transaksi →</span></a>
